#include<cstdio>
#include<cstring>
#include<iostream>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef unsigned long long ull;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10,Mod=1e9+7,inv2=500000004;
int S[26][N],a[26],b[26],inv[N],Inv[N];char s[N];int n;
inline void Hash(int c)
{
	int tmp=1;rep(0,n,i)inv[i]=tmp,tmp=(tmp<<1)%Mod;
	Inv[0]=1;tmp=inv2;rep(1,n,i)Inv[i]=tmp,tmp=1ll*tmp*inv2%Mod;
	int hsh=0;rep(1,n,i)hsh=(hsh<<1)%Mod+(s[i]==c+'a');
	S[c][1]=hsh;rep(2,n,i)
	{
		S[c][i]=(S[c][i-1]-((s[i-1]^(c+'a'))?0:inv[n-i+1])+Mod)%Mod;
	}
}
inline ull qry(int l,int r,int c)
{
	int res=(S[c][l]-S[c][r+1]+Mod)%Mod;
	res=1ll*res*Inv[n-r]%Mod;
	return res;
}
inline void print(ull k)
{
	if(k>1)print(k>>1);putchar((k&1)+'0'); 
}
int main()
{
	n=read();int m=read();scanf("%s",s+1);rep(0,25,i)Hash(i);
//	rep(1,n,i)std::cout<<Inv[i]<<' ';puts("");while(1)print(read()*Inv[1]),putchar('\n');
	while(m--)
	{
		int l1=read(),l2=read(),rr=read(),r1=l1+rr-1,r2=l2+rr-1;bool flag=0;
		rep(0,25,i)a[i]=qry(l1,r1,i),b[i]=qry(l2,r2,i);std::sort(a,a+26);std::sort(b,b+26);
//		drep(25,0,i)std::cout<<a[i]<<' ';puts("");drep(25,0,i)std::cout<<b[i]<<' ';puts(""); 
		drep(25,0,i)if(a[i]^b[i]){puts("NO");flag=1;break;}if(!flag)puts("YES");
	}
}
